export const getMonster = (key) => MONSTERS.find((m) => m.key === key)
export const crLabel = (cr) => (cr === 0.125 ? '1/8' : cr === 0.25 ? '1/4' : cr === 0.5 ? '1/2' : `${cr}`)
export const abilityModStr = (score) => {
  const m = Math.floor((score - 10) / 2)
  return `${score} (${m >= 0 ? '+' : ''}${m})`
}
